Usage in Prism App.xaml.cs:

protected override void RegisterTypes(IContainerRegistry containerRegistry)
{
    containerRegistry.AddFoxMapKit();
}

example.code:
var query = dbContext.Users
    .Where(u => u.IsActive)
    .ProjectTo<UserDto>()
    .OrderBy(dto => dto.Name);
var results = await query.ToListAsync();

var entity = dbContext.Tasks.Find(id);
entity.MapFrom(dto); // Updates entity in-place
await dbContext.SaveChangesAsync(); // EF Core detects changes
